(function(w){"use strict";const ID="loan";function compute(x){const p=Number(x.principal),annual=Number(x.rate),months=Number(x.months),method=x.method||"equal-payment";if(!Number.isFinite(p)||p<=0||!Number.isFinite(annual)||annual<0||!Number.isInteger(months)||months<=0)return{error:"대출금·금리·기간을 올바르게 입력해 주세요."};const r=annual/100/12;if(method==="equal-payment"){const payment=r===0?p/months:p*r*Math.pow(1+r,months)/(Math.pow(1+r,months)-1);const total=payment*months;return{first:payment,last:payment,total,interest:total-p}}const principalPart=p/months;const first=principalPart+p*r;const last=principalPart+principalPart*r;let interest=0;for(let i=0;i<months;i++)interest+=(p-principalPart*i)*r;return{first,last,total:p+interest,interest}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>대출금 (원)</label><input class="hm-calc-input" inputmode="numeric"></div><div class="hm-calc-field"><label>연 이자율 (%)</label><input class="hm-calc-input" inputmode="decimal"></div><div class="hm-calc-field"><label>대출기간 (개월)</label><input class="hm-calc-input" inputmode="numeric" placeholder="예: 36"></div><div class="hm-calc-field"><label>상환방식</label><select class="hm-calc-select"><option value="equal-payment">원리금균등</option><option value="equal-principal">원금균등</option></select></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">대출 계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div><p class="hm-calc-note">수수료·중도상환·거치기간 등은 반영하지 않은 단순 상환 시뮬레이션입니다.</p></div>`;const ins=root.querySelectorAll("input"),method=root.querySelector("select"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({principal:api.parseNumber(ins[0].value),rate:api.parseNumber(ins[1].value),months:Math.round(api.parseNumber(ins[2].value)),method:method.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("첫 달 예상 상환액",api.formatWon(r.first),`<dl><dt>마지막 달 예상 상환액</dt><dd>${api.formatWon(r.last)}</dd><dt>총 이자</dt><dd>${api.formatWon(r.interest)}</dd><dt>총 상환액</dt><dd>${api.formatWon(r.total)}</dd></dl>`));});}w.HM_CALC.register(ID,{compute,render});})(window);
